SESSION_PREFIX = "session:"
SESSION_EXPIRY = 3600  # 1 hour in seconds


class RedisSessionManager:
    """Manages user sessions stored in Redis."""

    def __init__(self, redis_conn, prefix=SESSION_PREFIX, expiry=SESSION_EXPIRY):
        self.redis = redis_conn
        self.prefix = prefix
        self.expiry = expiry

    def create_session(self, user_data):
        """Create a new session and return the session ID."""
        session_id = str(uuid.uuid4())
        key = f"{self.prefix}{session_id}"
        session_data = {
            "user_data": json.dumps(user_data),
            "created_at": datetime.utcnow().isoformat(),
            "last_accessed": datetime.utcnow().isoformat(),
        }
        # Use SET with expiry via pipeline for atomicity
        pipe = self.redis.pipeline()
        pipe.hset(key, mapping=session_data)
        pipe.expire(key, self.expiry)
        pipe.execute()
        return session_id

    def get_session(self, session_id):
        """Retrieve session data by session ID."""
        key = f"{self.prefix}{session_id}"
        session_data = self.redis.hgetall(key)
        if not session_data:
            return None
        # Update last accessed time and refresh TTL
        pipe = self.redis.pipeline()
        pipe.hset(key, "last_accessed", datetime.utcnow().isoformat())
        pipe.expire(key, self.expiry)
        pipe.execute()
        session_data["user_data"] = json.loads(session_data["user_data"])
        return session_data

    def update_session(self, session_id, user_data):
        """Update session data."""
        key = f"{self.prefix}{session_id}"
        if not self.redis.exists(key):
            return False
        pipe = self.redis.pipeline()
        pipe.hset(key, "user_data", json.dumps(user_data))
        pipe.hset(key, "last_accessed", datetime.utcnow().isoformat())
        pipe.expire(key, self.expiry)
        pipe.execute()
        return True

    def destroy_session(self, session_id):
        """Delete a session."""
        key = f"{self.prefix}{session_id}"
        return self.redis.delete(key) > 0

    def get_active_session_count(self):
        """Count active sessions (for monitoring)."""
        cursor = 0
        count = 0
        while True:
            cursor, keys = self.redis.scan(cursor, match=f"{self.prefix}*", count=100)
            count += len(keys)
            if cursor == 0:
                break
        return count


