CACHE_PREFIX = "cache:"
DEFAULT_CACHE_TTL = 300  # 5 minutes


def cache_result(ttl=DEFAULT_CACHE_TTL, prefix=CACHE_PREFIX, key_builder=None):
    """
    Caching decorator for expensive database queries or computations.

    Args:
        ttl: Time-to-live in seconds for cached results.
        prefix: Redis key prefix for cache entries.
        key_builder: Optional callable to build custom cache keys.
                     Receives (func, args, kwargs) and should return a string.
    """

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key
            if key_builder:
                cache_key_raw = key_builder(func, args, kwargs)
            else:
                # Default key: function name + hashed arguments
                args_str = json.dumps(
                    {"args": [str(a) for a in args], "kwargs": {k: str(v) for k, v in sorted(kwargs.items())}},
                    sort_keys=True,
                )
                args_hash = hashlib.md5(args_str.encode()).hexdigest()
                cache_key_raw = f"{func.__module__}.{func.__qualname__}:{args_hash}"

            cache_key = f"{prefix}{cache_key_raw}"

            # Try to get from cache
            try:
                cached = redis_pooled_client.get(cache_key)
                if cached is not None:
                    result = json.loads(cached)
                    # Optionally add cache hit metadata
                    if isinstance(result, dict):
                        result["_cache_hit"] = True
                    return result
            except (redis.RedisError, json.JSONDecodeError):
                # If Redis is down or data is corrupted, fall through to function
                pass

            # Execute the function
            result = func(*args, **kwargs)

            # Store in cache
            try:
                redis_pooled_client.set(cache_key, json.dumps(result), ex=ttl)
            except redis.RedisError:
                # If Redis is down, just return the result without caching
                pass

            return result

        # Add cache management methods to the wrapper
        def invalidate(*args, **kwargs):
            """Manually invalidate cache for specific arguments."""
            if key_builder:
                cache_key_raw = key_builder(func, args, kwargs)
            else:
                args_str = json.dumps(
                    {"args": [str(a) for a in args], "kwargs": {k: str(v) for k, v in sorted(kwargs.items())}},
                    sort_keys=True,
                )
                args_hash = hashlib.md5(args_str.encode()).hexdigest()
                cache_key_raw = f"{func.__module__}.{func.__qualname__}:{args_hash}"
            cache_key = f"{prefix}{cache_key_raw}"
            return redis_pooled_client.delete(cache_key)

        def invalidate_all():
            """Invalidate all cache entries for this function."""
            pattern = f"{prefix}{func.__module__}.{func.__qualname__}:*"
            cursor = 0
            deleted = 0
            while True:
                cursor, keys = redis_pooled_client.scan(cursor, match=pattern, count=100)
                if keys:
                    deleted += redis_pooled_client.delete(*keys)
                if cursor == 0:
                    break
            return deleted

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all
        return wrapper

    return decorator


