def rate_limit(max_requests=100, window_seconds=60):
    """Rate limiting decorator using Redis sliding window."""

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Use IP address or session as identifier
            client_id = request.headers.get("X-Forwarded-For", request.remote_addr)
            key = f"ratelimit:{func.__name__}:{client_id}"
            now = time.time()

            try:
                pipe = redis_pooled_client.pipeline()
                # Remove old entries outside the window
                pipe.zremrangebyscore(key, 0, now - window_seconds)
                # Add current request
                pipe.zadd(key, {str(now): now})
                # Count requests in window
                pipe.zcard(key)
                # Set expiry on the key
                pipe.expire(key, window_seconds)
                results = pipe.execute()
                request_count = results[2]

                if request_count > max_requests:
                    return jsonify({
                        "error": "Rate limit exceeded",
                        "retry_after": window_seconds,
                    }), 429
            except redis.RedisError:
                # If Redis is down, allow the request
                pass

            return func(*args, **kwargs)

        return wrapper

    return decorator


