@app.route("/api/session/me", methods=["GET"])
def get_current_session():
    """Get current session data."""
    if not g.session_data:
        return jsonify({"error": "No active session. Please login."}), 401

    return jsonify({
        "session_id": g.session_id,
        "session": g.session_data,
    })


@app.route("/api/session/update", methods=["PUT"])
def update_current_session():
    """Update current session data."""
    if not g.session_data:
        return jsonify({"error": "No active session. Please login."}), 401

    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body is required"}), 400

    # Merge new data with existing session user data
    current_user_data = g.session_data["user_data"]
    current_user_data.update(data)

    success = session_manager.update_session(g.session_id, current_user_data)
    if success:
        return jsonify({"message": "Session updated", "user_data": current_user_data})
    return jsonify({"error": "Failed to update session"}), 500


@app.route("/api/session/logout", methods=["POST"])
def logout():
    """Destroy current session (logout)."""
    if not g.session_id:
        return jsonify({"error": "No active session"}), 400

    session_manager.destroy_session(g.session_id)
    response = jsonify({"message": "Logged out successfully"})
    response.delete_cookie("session_id")
    return response


