# ---- Simple Key-Value Session Store (SET/GET demonstration) ----

@app.route("/api/kv/set", methods=["POST"])
def kv_set():
    """Store a key-value pair in Redis using SET command."""
    data = request.get_json()
    if not data or "key" not in data or "value" not in data:
        return jsonify({"error": "key and value are required"}), 400

    key = f"kv:{data['key']}"
    ttl = data.get("ttl", 3600)

    redis_pooled_client.set(key, json.dumps(data["value"]), ex=ttl)

    return jsonify({
        "message": "Stored successfully",
        "key": data["key"],
        "ttl": ttl,
    })


@app.route("/api/kv/get/<key>", methods=["GET"])
def kv_get(key):
    """Retrieve a value from Redis using GET command."""
    redis_key = f"kv:{key}"
    value = redis_pooled_client.get(redis_key)

    if value is None:
        return jsonify({"error": "Key not found"}), 404

    ttl = redis_pooled_client.ttl(redis_key)

    return jsonify({
        "key": key,
        "value": json.loads(value),
        "ttl_remaining": ttl,
    })


@app.route("/api/kv/delete/<key>", methods=["DELETE"])
def kv_delete(key):
    """Delete a key from Redis."""
    redis_key = f"kv:{key}"
    deleted = redis_pooled_client.delete(redis_key)

    if deleted:
        return jsonify({"message": f"Key '{key}' deleted"})
    return jsonify({"error": "Key not found"}), 404


